using UnityEngine;

/// <summary>
/// Sprint (Cavalo "Sprint controlado", Guepardo "Sprint extremo", Avestruz
/// "Corrida estável", Orca "Nado rápido" — P5): enquanto o botão de habilidade
/// está seguro, multiplica a velocidade horizontal do PlayerMotor2D por
/// "sprintSpeedMultiplier" da forma (P1).
///
/// Activado via PrimaryAbility.Sprint: AbilityRouter chama StartSprint() em
/// OnAbilityPressed e StopSprint() em OnAbilityReleased.
/// </summary>
[RequireComponent(typeof(PlayerMotor2D))]
public class SprintAbility : MonoBehaviour, IFormAbility, IAbility, IActiveAbility
{
    private PlayerMotor2D motor;

    private bool enabledForForm;
    private float multiplier = 1.5f;
    private bool sprinting;

    /// <summary>true enquanto o sprint está activo.</summary>
    public bool IsSprinting => sprinting;

    private void Awake()
    {
        motor = GetComponent<PlayerMotor2D>();
    }

    public void ConfigureFromForm(AnimalFormData form)
    {
        enabledForForm = form != null && form.primaryAbility == PrimaryAbility.Sprint;
        multiplier = form != null ? Mathf.Max(1f, form.sprintSpeedMultiplier) : 1.5f;

        // Troca de forma a meio do sprint: o motor já repõe o multiplicador a 1.
        sprinting = false;
    }

    public void StartSprint()
    {
        if (!enabledForForm || sprinting) return;
        if (motor.MovementLocked) return;

        sprinting = true;
        motor.SetSpeedMultiplier(multiplier);
    }

    public void StopSprint()
    {
        if (!sprinting) return;

        sprinting = false;
        motor.SetSpeedMultiplier(1f);
    }

    // ---- IAbility / IActiveAbility (Tarefa #34 — HUD) ----
    // "Hold": Activate/Release mapeiam para Start/StopSprint; Cancel também
    // termina o sprint. Sem cooldown.
    void IAbility.Activate() => StartSprint();
    void IAbility.Release() => StopSprint();
    public void Cancel(AbilityCancelReason reason) => StopSprint();
    public float CooldownRemaining => 0f;
    bool IAbility.IsActive => sprinting;
    public float CooldownDuration => 0f;
    public bool CanActivate => enabledForForm && !sprinting && !motor.MovementLocked;

    /// <summary>AnimalsDebugPanel — sem cooldown próprio (no-op).</summary>
    public void ResetCooldown() { }
}
